"""
mkt-original — Numbers chapters 27–29
Run: python3 scripts/zc-original-numbers-27-29.py

Ch 27: daughters of Zelophehad (vv.1-11), Moses's death announced (vv.12-14),
       prayer for a successor (vv.15-17), Joshua commissioned (vv.18-23)
Ch 28: festival sacrifice calendar — daily, Sabbath, New Moon, Passover, Weeks
Ch 29: seventh-month festivals — Trumpets, Atonement, Tabernacles (decreasing bulls),
       eighth-day closing assembly

Key term decisions:
- nachalah = 'inheritance/holding' (estate, covenantal share)
- hod = 'authority/splendor' (transferred to Joshua — partial, not full)
- tamid = 'regular' (perpetual unbroken rhythm)
- re'ach nichoach = 'pleasing aroma' (retained; sensory-theological term)
- atzeret = 'closing assembly' (Hb 'hold back/gather in'; eighth-day Sukkot)
- 'innitem et nafshoteikhem = 'afflict your souls' (Yom Kippur; MKT retains literal idiom)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NUMBERS = {
  "27": {
    "1": "<p><strong>בְּנוֹת צְלָפְחָד</strong> (<em>b'not tzlofchad</em>, H1121+H6765): 'daughters of Zelophehad.' The five daughters are named individually — Mahlah, Noah, Hoglah, Milcah, Tirzah — an unusual honour in the legal narrative: women are granted full juridical standing as claimants. The genealogy traces through Manasseh son of Joseph, establishing their lineage in the Josephite tribes whose land allotment will fall west and east of Jordan. The naming reflects the gravity of the case: these are not anonymous suppliants but named heirs.</p>",
    "2": "<p><strong>פֶּתַח אֹהֶל מוֹעֵד</strong> (<em>petach ohel mo'ed</em>, H6607+H168+H4150): 'entrance of the tent of meeting.' The daughters present their case at the precise threshold of covenantal adjudication — the same location where Moses meets YHWH and where Israel's legal disputes are brought for divine resolution. Standing <em>lifnei</em> Moses, Eleazar the priest, the leaders, and the whole congregation mirrors the full judicial structure: the case is brought before every level of authority simultaneously, ensuring its ruling will have maximum binding force.</p>",
    "3": "<p><strong>חֶטְאוֹ</strong> (<em>chet'o</em>, H2399): 'his own sin.' The daughters carefully dissociate their father from Korah's rebellion — he died for <em>his own</em> sin, not in solidarity with an act of communal apostasy. This distinction matters legally: property forfeited by rebels (Korah's company) might be treated differently from estates of those who simply died in the wilderness. The daughters are not petitioning on behalf of a rebel's legacy but for an ordinary estate. <em>benim lo-hayu lo</em> (he had no sons) — the problem is purely structural within the inheritance code, not moral.</p>",
    "4": "<p><strong>יִגָּרַע</strong> (<em>yigara'</em>, H1639): 'be diminished/blotted out.' The daughters articulate the theological stakes: if their father's name disappears from his clan, his identity — his <em>shem</em> — is erased from Israel. In Hebrew thought, the survival of a name is closely linked to the survival of a person's legacy and participation in covenant community. The <em>nachalah</em> (H5159, inheritance/holding) is not merely economic property but the concrete, land-based form of a man's covenantal identity in Israel. To lose it is to lose presence in YHWH's land.</p>",
    "5": "<p><strong>וַיַּקְרֵב מֹשֶׁה</strong> (<em>vayakriv moshe</em>, H7126): 'Moses brought/drew near their case.' The verb <em>qarav</em> (draw near, approach) is the same root as <em>qorban</em> (offering). Moses performs an act structurally analogous to presenting an offering: he brings the daughters' legal claim into YHWH's presence for adjudication. This framing treats legal justice as an act of drawing near to God — juridical process and priestly access share the same vocabulary.</p>",
    "6": "<p><strong>וַיְדַבֵּר יְהוָה אֶל-מֹשֶׁה</strong> (<em>vay'daber YHWH el-moshe</em>): 'YHWH spoke to Moses.' The divine adjudication is direct and immediate. YHWH does not deliberate or refer the case further — the ruling comes as a clear word. This reflects the characterization of Moses's unique access to YHWH (Num 12:6-8: face to face, not in riddles). The legal case becomes a direct encounter between human petition and divine word.</p>",
    "7": "<p><strong>כֵּן</strong> (<em>ken</em>, H3651): 'rightly/thus.' YHWH's single-word juridical affirmation: the daughters' claim is <em>ken</em> — correct, right, properly ordered. The fullest possible validation. <strong>נָתֹן תִּתֵּן</strong> (<em>naton titen</em>, H5414): 'you shall certainly give' — the infinitive absolute before the finite verb creates an emphatic command with no qualification. YHWH overturns the patrilineal default not by abolishing it but by extending <em>nachalah</em> to daughters when there are no sons. The inheritance passes <em>ba'avotam</em> (among their father's brothers — i.e., into the same tribe), preserving tribal integrity.</p>",
    "8": "<p><strong>חֻקַּת מִשְׁפָּט</strong> (<em>chuqat mishpat</em>, H2708+H4941): 'a statute of judgment / a legal ordinance.' YHWH elevates the daughters' case into permanent legislative precedent. <em>Chuqah</em> denotes a binding statute (as opposed to a case-by-case ruling); <em>mishpat</em> is the legal verdict or judicial decision. The daughter-inheritance clause becomes codified law for all Israel: if a man dies with no son, his inheritance passes to his daughter. The daughters' boldness in approaching the tent of meeting produces lasting structural change in Israelite law.</p>",
    "9": "<p><strong>אֶחָיו</strong> (<em>echav</em>, H251): 'his brothers.' The inheritance cascade continues: no son → daughter (v.8); no daughter → brothers. The cascade logic follows the concentric circles of family solidarity: immediate descendants, then lateral kin. Each step tests whether the name and estate can be preserved within the tightest available covenantal unit before passing outward.</p>",
    "10": "<p><strong>אֲחֵי אָבִיו</strong> (<em>achei aviv</em>, H251+H1): 'his father's brothers.' No brothers → father's brothers. The system is designed to exhaust every possible route of preservation before the name/estate falls out of the immediate family network. The phrase <em>la'achuzzat nachalah</em> recurs — 'as a holding of inheritance' — emphasizing that what passes is not mere property but covenantal estate.</p>",
    "11": "<p><strong>שְׁאֵרוֹ הַקָּרֹב</strong> (<em>she'ero haqarov</em>, H7607+H7138): 'his nearest relative.' The final fallback — if father's brothers are absent, the nearest kinsman receives. <em>She'er</em> (flesh-relation, near-kin) is the same root that underlies the <em>go'el</em> (kinsman-redeemer) system. The inheritance law is not an arbitrary cascade but a structured expression of the kin-solidarity that permeates Israel's covenantal social order. The ordinance closes with the signature formula: <em>chuqat mishpat</em> — a statute of judgment for all Israel through all generations.</p>",
    "12": "<p><strong>הָרֵי הָעֲבָרִים</strong> (<em>harei ha'avarim</em>, H2022+H5682): 'mountains of Abarim.' The range east of Jordan from which Moses will see Canaan — the same geography as Nebo/Pisgah (Deut 32:49; 34:1). YHWH's command is not punishment but consolation: <em>re'eh</em> (see it), the visual possession of what Moses cannot enter. In Hebrew covenantal thought, seeing the land is itself meaningful — a form of having arrived, even if not of entering. YHWH honours Moses's life's work by granting him sight of the goal.</p>",
    "13": "<p><strong>נֶאֱסַפְתָּ אֶל-עַמֶּיךָ</strong> (<em>ne'esafta el-amekha</em>, H622): 'you will be gathered to your people.' The death-euphemism used for both Aaron (Num 20:24) and the patriarchs. <em>Asaf</em> (gather, receive in) frames death as homecoming rather than extinction — the dead join the company of covenant ancestors. The formula acknowledges continuity beyond individual life: Moses will be <em>asher</em> — received into — the corporate identity of Israel's dead.</p>",
    "14": "<p><strong>מְרִיתֶם אֶת-פִּי</strong> (<em>meritem et-pi</em>, H4784): 'you rebelled against my command/mouth.' <em>Marah</em> (to be bitter, to rebel) is the root: Moses and Aaron failed at Meribah-kadesh (<em>merivat kadesh</em>) — the site whose name encodes the quarrel (<em>merivah</em>, H4808). <strong>לֹא-קִדַּשְׁתֶּם אוֹתִי</strong> (<em>lo-qidashtem oti</em>, H6942): 'you did not sanctify/hallow me.' The specific failure: striking the rock rather than speaking to it (Num 20:8-11) failed to <em>hiqdish</em> YHWH before Israel — failed to make him holy in the sight of the congregation. Moses's punishment is the consequence of a public act of unfaithfulness to the specific command given.</p>",
    "15": "<p><strong>וַיְדַבֵּר מֹשֶׁה אֶל-יְהוָה</strong> (<em>vay'daber moshe el-YHWH</em>): 'Moses spoke TO YHWH.' The preposition is noteworthy: Moses speaks <em>el</em> (toward, to) YHWH — prayer, petition, address. His response to the announcement of his death is not protest or bargaining but intercession for the community. This is the measure of Moses's greatness: even as his own death is pronounced, his first utterance is concern for the flock he will leave behind.</p>",
    "16": "<p><strong>אֱלֹהֵי הָרוּחֹת לְכָל-בָּשָׂר</strong> (<em>elohei haruchot lekhol basar</em>, H430+H7307+H1320): 'God of the spirits of all flesh.' This extraordinary compound divine title appears only twice in Numbers: here and at 16:22 (Moses and Aaron's intercession before Korah's judgment). The epithet asserts YHWH's sovereignty over every living being's inner animating principle — every <em>ruach</em> (spirit/breath) in every embodied creature belongs to him. Moses invokes this title to ground his request for a shepherd: the God who holds every <em>ruach</em> can certainly designate one man to carry the community's weight.</p>",
    "17": "<p><strong>אֲשֶׁר-יֵצֵא לִפְנֵיהֶם וַאֲשֶׁר יָבֹא לִפְנֵיהֶם</strong> (<em>asher yetze lifneihem va'asher yavo lifneihem</em>): 'who will go out before them and come in before them.' The phrase is the standard idiom for military/civic leadership: leading troops into and out of battle, going ahead of the people in all their movements. Moses describes a shepherd-king. <strong>כְּצֹאן אֲשֶׁר אֵין-לָהֶם רֹעֶה</strong> (<em>ketszon asher ein lahem ro'eh</em>): 'like sheep that have no shepherd' — the image Jesus will use for Israel in Matt 9:36 and Mark 6:34. Moses is praying for what becomes the central shepherd-imagery of the prophets and Gospels.</p>",
    "18": "<p><strong>אִישׁ אֲשֶׁר-רוּחַ בּוֹ</strong> (<em>ish asher ruach bo</em>, H7307): 'a man in whom the Spirit resides/is.' YHWH's criterion for leadership is not lineage, age, or military record but the presence of <em>ruach</em>. Joshua had been Moses's aide since youth (Exod 24:13; 33:11) and was one of the faithful spies (Num 14:6-9). But the qualification named here is internal — the <em>ruach</em> within him. <strong>סָמַכְתָּ אֶת-יָדְךָ עָלָיו</strong> (<em>samakhta et-yadkha alav</em>, H5564): 'lay your hand on him' — singular <em>yadkha</em> (your hand), marking this as a partial transfer of authority, contrasted with the bilateral laying of both hands at Lev 16:21.</p>",
    "19": "<p><strong>וְהַעֲמַדְתָּ אֹתוֹ לִפְנֵי</strong> (<em>veha'amadta oto lifnei</em>, H5975): 'present/station him before.' Joshua is to be presented before Eleazar the priest and the whole congregation — the same audience as the daughters of Zelophehad (v.2). <em>Tzivah</em> (H6680, commission/charge) — Moses is to charge/commission Joshua publicly, <em>le'eineihem</em> (in their eyes/sight). The public installation is essential: authority transferred privately would carry less weight; the congregation must witness the moment of transference.</p>",
    "20": "<p><strong>מֵהוֹדְךָ עָלָיו</strong> (<em>mehodkha alav</em>, H1935): 'some of your splendor/authority upon him.' <em>Hod</em> (splendor, majesty, authority) — the word used of royal dignity and divine majesty (Ps 104:1; 145:5). The <em>mem</em> prefix is partitive: some (not all) of Moses's authority is transferred. The text signals continuity-with-diminution: Joshua will be Israel's leader but will operate through Eleazar's Urim rather than direct face-to-face divine communication. A new era begins with a different mode of divine access.</p>",
    "21": "<p><strong>וְלִפְנֵי אֶלְעָזָר הַכֹּהֵן יַעֲמֹד וְשָׁאַל לוֹ בְּמִשְׁפַּט הָאוּרִים</strong> (<em>...umishpat ha'urim</em>, H224): 'he shall inquire for him by the judgment of the Urim.' Moses communicated with YHWH directly (Num 12:8: face to face, not in riddles); Joshua will consult through the high priest's Urim. The shift is significant: the prophetic immediacy of Moses's era gives way to mediated, priestly oracular inquiry. The <em>mishpat</em> of the Urim — the judicial decision rendered through the ephod — becomes Joshua's mode of receiving divine guidance. The transition embodies a shift in the nature of leadership itself.</p>",
    "22": "<p><strong>וַיַּעַשׂ מֹשֶׁה כַּאֲשֶׁר צִוָּה יְהוָה אֹתוֹ</strong> (<em>vaya'as moshe ka'asher tzivah YHWH oto</em>): 'Moses did as YHWH commanded him.' The completion formula that closes nearly every significant Mosaic action throughout the Pentateuch (cf. Exod 40:16; Num 17:11). Moses's obedience here is particularly poignant: having just heard his own death sentence, he immediately carries out the very act that installs his successor. Faithfulness to YHWH's command takes precedence over personal grief.</p>",
    "23": "<p><strong>וַיִּסְמֹךְ אֶת-יָדָיו עָלָיו</strong> (<em>vayismok et-yadav alav</em>, H5564): 'he laid his hands on him.' The act of commissioning is complete. <em>Samakh</em> (to support, lean, lay) — the laying of hands transfers weight, authority, and identity from the one laying to the one receiving. The narrative closes with the double citation: 'as the LORD commanded through Moses' — the closing formula matches the opening command. The authority passes lawfully, through the prophetic-priestly chain, grounded in YHWH's own appointment. Joshua's succession is not a human promotion but a divine installation.</p>"
  },
  "28": {
    "1": "<p><strong>וַיְדַבֵּר יְהוָה אֶל-מֹשֶׁה</strong> (<em>vay'daber YHWH el-moshe</em>): 'YHWH spoke to Moses.' The standard revelation formula introduces a lengthy liturgical legislation. The placement is deliberate: immediately after Joshua's commissioning (ch.27), YHWH gives Israel the complete offering calendar. The new leader will inherit not only authority but a fully specified liturgical system — the rhythm of sacrifice that structures Israel's time.</p>",
    "2": "<p><strong>קָרְבָּנִי לַחְמִי לְאִשַּׁי</strong> (<em>qorbani lachmi le'ishai</em>, H7133+H3899+H801): 'my offering — the food of my fire offerings.' <em>Qorban</em> (offering, H7133) derives from <em>qarav</em> (draw near): the offering is what brings Israel near to YHWH and YHWH's presence near to Israel. <em>Lechem</em> (food/bread) here is anthropomorphic — YHWH describes the offerings as 'my food,' language also found in Ezekiel. It is not literalism but a relational idiom: the offerings are the table-fellowship of the covenant. <strong>בְּמוֹעֲדוֹ</strong> (<em>bemoe'do</em>, H4150): 'at its appointed time' — the offerings must be presented precisely at the times YHWH has designated. <em>Mo'ed</em> governs the entire calendar of worship.</p>",
    "3": "<p><strong>עֹלַת תָּמִיד</strong> (<em>olat tamid</em>, H5930+H8548): 'the regular/perpetual burnt offering.' <em>Tamid</em> (continual, regular, perpetual) — the unbroken daily rhythm of sacrifice that marks Israel's ongoing covenant relationship. <em>Olah</em> (burnt offering) derives from <em>alah</em> (go up): the entire animal ascends to YHWH in smoke. <em>Benei shanah temimim</em> (H8549) — 'yearling lambs without blemish': the offering must be at the peak of physical perfection, a recurring requirement that will find its ultimate expression in the NT's 'lamb without blemish' (1 Pet 1:19).</p>",
    "4": "<p><strong>אֶת-הַכֶּבֶשׂ הָאֶחָד תַּעֲשֶׂה בַבֹּקֶר</strong> (<em>et-hakeves ha'echad ta'aseh veboqer</em>): 'the one lamb in the morning.' The twice-daily sacrifice establishes morning and evening as the fixed poles of Israel's liturgical day. <strong>בֵּין הָעַרְבַּיִם</strong> (<em>bein ha'arbayim</em>, H6153): 'between the evenings' — the period of late afternoon when the sun begins to descend. The same phrase governs the time of the Passover slaughter (Exod 12:6). The daily rhythm of Israel's sacrifice is synchronized with the rhythms of light itself: dawn and dusk as the natural clock of covenantal worship.</p>",
    "5": "<p><strong>עִשָּׂרוֹן סֹלֶת</strong> (<em>issaron soleth</em>, H6241+H5560): 'one-tenth of an ephah of fine flour.' The <em>minhah</em> (grain offering, H4503) accompanies the animal sacrifice. <em>Soleth</em> (fine flour) — the highest-grade flour, sifted. <strong>שֶׁמֶן כָּתִית</strong> (<em>shemen katit</em>, H8081+H3795): 'pressed/beaten oil' — olive oil produced by the first pressing, the purest grade. The specificity of quality (fine not coarse flour; pressed not crushed oil) signals that the best of Israel's agricultural produce belongs at YHWH's table. Worship is not a residual claim on what remains after human needs are met.</p>",
    "6": "<p><strong>עֹלַת תָּמִיד הָעֲשֻׂיָה בְּהַר סִינַי</strong> (<em>olat tamid ha'asuyah behar sinai</em>): 'the regular burnt offering, made at Mount Sinai.' The authority for the daily sacrifice is grounded explicitly in the Sinai revelation — the apex of YHWH's self-disclosure to Israel. This is not a new institution but the perpetuation of what was established at the moment of covenant-making. The <em>re'ach nichoach</em> (H7381+H5207, 'pleasing aroma') — a sensory-theological idiom throughout the sacrifice legislation: the offerings please YHWH not as literal nutrition but as a relational gesture of devotion ascending to him.</p>",
    "7": "<p><strong>שֵׁכָר</strong> (<em>shekhar</em>, H7941): 'fermented/strong drink.' The drink offering is poured out in the holy place. <em>Shekhar</em> (usually 'strong drink,' distinct from <em>yayin</em>/wine) appears in cultic contexts as a libation. <strong>בַּקֹּדֶשׁ הַסֵּךְ</strong> (<em>baqodesh hassekh</em>): 'pour it out in holiness' — the holy place is the site of the libation, emphasizing that even the liquid poured on the ground is a sacred act. The drink offering is not merely incidental but integral to the complete sacrificial rite.</p>",
    "8": "<p><strong>כְּמִנְחַת הַבֹּקֶר וּכְנִסְכּוֹ</strong> (<em>keminchat haboqer ukhnisc'o</em>): 'like the grain offering of the morning and its drink offering.' The evening sacrifice precisely mirrors the morning — same animal, same grain offering, same drink offering. The symmetry creates a complete liturgical frame: morning and evening sacrifices bracket Israel's day with covenantal worship. The repetition formula signals that the <em>tamid</em> is not two distinct rites but one continuous act spread across the day.</p>",
    "9": "<p><strong>וּבְיוֹם הַשַּׁבָּת</strong> (<em>uvyom hashabbat</em>): 'on the Sabbath day.' The Sabbath sacrifice doubles the daily offering: two lambs instead of one, two-tenths of flour instead of one. The Sabbath is not a suspension of sacrifice but an amplification — rest for labour and increase in worship. The Sabbath <em>olah</em> is presented <em>al-olat hatamid</em> (in addition to the regular burnt offering): the Sabbath offering does not replace the daily sacrifice but layers on top of it. <em>Mishpatam</em> — 'their due' — each offering has its proper, prescribed measure.</p>",
    "10": "<p><strong>עֹלַת שַׁבַּת בְּשַׁבַּתּוֹ</strong> (<em>olat shabbat b'shabbato</em>): 'the Sabbath burnt offering on its [every] Sabbath.' The doubled noun emphasizes regularity: every Sabbath, without exception, has its specific offering. The phrase <em>milevad olat hatamid v'niskah</em> — 'in addition to the regular burnt offering and its drink offering' — establishes the structural principle governing the entire calendar: each higher-order occasion adds offerings to the base of the perpetual daily sacrifice, never replacing it. The liturgical calendar builds upward from the <em>tamid</em> as its foundation.</p>",
    "11": "<p><strong>וּבְרָאשֵׁי חָדְשֵׁיכֶם</strong> (<em>uvra'shei chodsheikhem</em>, H7218+H2320): 'at the beginning of your months / at your new moons.' <em>Rosh chodesh</em> (new moon, lit. 'head of the month') marks the lunar calendar's reset: the first appearance of the new moon. The New Moon offering is substantially larger than the daily or Sabbath sacrifice: two young bulls, one ram, seven yearling lambs. The new moon was a significant commercial rest-day in Israel (Amos 8:5) as well as a liturgical occasion. Its offerings signal that the lunar calendar itself is ordered by YHWH's appointment.</p>",
    "12": "<p><strong>שְׁלֹשָׁה עֶשְׂרֹנִים</strong> (<em>sheloshah esronim</em>, H6241): 'three-tenths of an ephah.' The grain-offering proportions scale with the animal: three-tenths per bull, two-tenths per ram (v.12), one-tenth per lamb (v.13). The graduated scale expresses proportional honour — larger animals bring larger grain tributes. <em>Soleth belulah vashemen</em> (fine flour mixed with oil) — the standard formula for the <em>minhah</em>; the mixing of grain and oil is a consistent cultic requirement throughout the sacrificial legislation.</p>",
    "13": "<p><strong>עִשָּׂרוֹן עִשָּׂרוֹן לַכֶּבֶשׂ הָאֶחָד</strong> (<em>issaron issaron lakeves ha'echad</em>): 'one-tenth for each individual lamb.' The double noun (<em>issaron issaron</em>) distributes the measure: one-tenth per lamb, separately. The seven lambs each receive their own portion. The meticulous proportionality of the sacrifice system — animals and their grain and drink offerings precisely calibrated — reflects a theology of ordered worship: YHWH's service is not improvised but specified, and precision in worship honours the God who specifies it.</p>",
    "14": "<p><strong>נִסְכֵּיהֶם</strong> (<em>niskeihem</em>, H5262): 'their drink offerings.' The New Moon drink offering specification: half a <em>hin</em> of wine (<em>yayin</em>, H3196) per bull, a third per ram, a quarter per lamb. Here <em>yayin</em> (wine) replaces <em>shekhar</em> (v.7's strong drink) — the New Moon gets wine. <em>Zot olat chodesh b'chodsho</em> — 'this is the burnt offering of each month at its month' — the closing formula for the New Moon legislation.</p>",
    "15": "<p><strong>וּשְׂעִיר עִזִּים אֶחָד לְחַטָּאת</strong> (<em>use'ir izzim echad lachatta't</em>, H8163+H5795+H2403): 'one male goat as a sin offering.' The <em>chatta't</em> (H2403, sin offering) — from <em>chata'</em> (to miss the mark, fail, sin) — makes corporate <em>kipper</em> (atonement) for the community each month. The monthly sin offering acknowledges that over the course of a month Israel accumulates corporate moral debt that requires expiation. The goat is offered <em>milevad olat hatamid</em> — in addition to the perpetual offering — underlining that the sin offering supplements rather than substitutes the daily burnt offering.</p>",
    "16": "<p><strong>פֶּסַח לַיהוָה</strong> (<em>pesach la-YHWH</em>, H6453): 'Passover to YHWH.' <em>Pesach</em> — the term for the festival and for the sacrificial animal — derives from <em>pasach</em> (H6452): to pass over (spare), or possibly to protect by hovering. The Passover falls on the 14th of the first month (Nisan/Abib), marking the anniversary of the exodus. The brevity of this verse — two words plus a date — is notable: the Passover itself needs no extended legislative treatment here because it was fully legislated in Exod 12. This is a calendar entry, not a new ordinance.</p>",
    "17": "<p><strong>וּבַחֲמִשָּׁה עָשָׂר יוֹם לַחֹדֶשׁ הַזֶּה חָג</strong> (<em>uvachamisha asar yom lachodesh hazeh chag</em>, H2282): 'on the 15th of this month is the feast.' <em>Chag</em> (H2282, feast, pilgrimage feast) — from <em>chagag</em> (to celebrate, dance in a circle). The three <em>chagim</em> (Passover/Unleavened Bread, Weeks, Tabernacles) were pilgrimage festivals requiring appearance at the sanctuary. <em>Matzot</em> (H4682, unleavened bread) — eaten for seven days from the 15th: the departure bread that commemorates the hasty exodus, leaving no time for dough to rise (Exod 12:39).</p>",
    "18": "<p><strong>בַּיּוֹם הָרִאשׁוֹן מִקְרָא-קֹדֶשׁ</strong> (<em>bayom harishon miqra-qodesh</em>, H4744+H6944): 'on the first day a holy assembly/convocation.' <em>Miqra</em> (H4744) — sacred assembly, convocation, that which is called together — from <em>qara</em> (to call, proclaim). The holy assembly marks the first and seventh days of Unleavened Bread as days of complete liturgical community. <strong>כָּל-מְלֶאכֶת עֲבֹדָה לֹא תַעֲשׂוּ</strong> (<em>kol melechet avodah lo ta'asu</em>): 'no laborious work shall you do' — the festival days share the Sabbath's prohibition on regular work, though the exact scope differs.</p>",
    "19": "<p><strong>וְהִקְרַבְתֶּם אִשֶּׁה</strong> (<em>vehiqravtem isheh</em>, H7126+H801): 'you shall present a fire offering.' The Passover week burnt offering is substantial: two bulls, one ram, seven yearling lambs — all without blemish. The festival-specific offering stacks atop the daily and monthly offerings that continue throughout. The number of animals reflects the importance of the occasion: Passover week is the highest point of Israel's liturgical year, commemorating YHWH's act of redemption from Egypt.</p>",
    "20": "<p><strong>מִנְחָתָם</strong> (<em>minchatam</em>, H4503): 'their grain offering.' The grain offering proportions for Passover week: three-tenths per bull, two-tenths per ram. These proportions are consistent with the New Moon offerings (v.12-13), establishing a standard measure that applies across major festivals. Consistency in proportions reflects a theology of ordered worship: the same God who created cosmic order (Gen 1) structures his worship with mathematical precision.</p>",
    "21": "<p><strong>עִשָּׂרוֹן תַּעֲשֶׂה לַכֶּבֶשׂ הָאֶחָד</strong> (<em>issaron ta'aseh lakeves ha'echad</em>): 'one-tenth shall you make for each lamb.' The seven yearling lambs each receive one-tenth of an ephah of fine flour. The repeated specification (<em>lashivat hak'vasim</em>, for the seven lambs) ensures no lamb is overlooked in the offering system. Precision in worship is itself a form of honour: each animal receives its proper due, not a collective approximation.</p>",
    "22": "<p><strong>וּשְׂעִיר-עִזִּים אֶחָד לְחַטָּאת</strong> (<em>use'ir-izzim echad lachatta't</em>): 'one male goat as a sin offering.' The <em>chatta't</em> accompanies every major festival offering in the calendar. Its consistent presence signals that no festival — not even the joyous Passover — is approached without an acknowledgment of communal sin and the need for atonement. The festival's joy and the sin offering's gravity coexist: Israel celebrates YHWH's saving acts while simultaneously acknowledging its own inadequacy before him.</p>",
    "23": "<p><strong>מִלְּבַד עֹלַת הַבֹּקֶר</strong> (<em>milevad olat haboqer</em>): 'in addition to the morning burnt offering.' The <em>milevad</em> ('besides/in addition to') principle structures the entire sacrificial calendar: higher-order occasions accumulate offerings on top of the base daily sacrifice, never replacing it. The morning <em>tamid</em> continues to be offered even during Passover week; the festival offering is additional, not substitutionary. This layering reflects the principle that special occasions intensify rather than replace ordinary covenantal worship.</p>",
    "24": "<p><strong>כָּכָה תַּעֲשׂוּ לַיּוֹם שִׁבְעַת יָמִים</strong> (<em>kakah ta'asu layom shivat yamim</em>): 'in this manner you shall do each day for seven days.' The offering pattern established for the first day of Unleavened Bread is repeated each day through the seven-day festival. <em>Lechem isheh re'ach nichoach la-YHWH</em> — 'the food of a fire offering, a pleasing aroma to YHWH' — the relational vocabulary of worship persists throughout the repetition. Worship is not diminished by regularity; the <em>tamid</em> is the <em>tamid</em> precisely because it is repeated without variation.</p>",
    "25": "<p><strong>וּבַיּוֹם הַשְּׁבִיעִי מִקְרָא-קֹדֶשׁ יִהְיֶה לָכֶם</strong> (<em>uvayom hashvi'i miqra-qodesh yihyeh lakhem</em>): 'on the seventh day a holy assembly shall be for you.' Unleavened Bread ends as it began — with a holy assembly and cessation of laborious work. The seven-day festival is bracketed by <em>miqra-qodesh</em> on its first and last days, creating a liturgical frame. The week of unleavened bread, like the first creation week, ends with a day set apart for sacred assembly.</p>",
    "26": "<p><strong>וּבְיוֹם הַבִּכּוּרִים</strong> (<em>uvyom habikkurim</em>, H1061): 'on the day of firstfruits.' Shavuot (Festival of Weeks) — fifty days after Passover — is introduced as the day of <em>bikkurim</em> (firstfruits, H1061). <em>Minchah chadashah la-YHWH</em> — 'a new grain offering to YHWH' — at Weeks, the new harvest's firstfruits are formally presented: the first grain of the new crop is YHWH's before any human consumption. <em>Miqra-qodesh</em> again — the pilgrimage feast day is a holy assembly, requiring cessation of laborious work.</p>",
    "27": "<p><strong>וְהִקְרַבְתֶּם עוֹלָה לְרֵיחַ נִיחֹחַ</strong> (<em>vehiqravtem olah lere'ach nichoach</em>): 'you shall present a burnt offering as a pleasing aroma.' Shavuot's offering matches the Passover week structure: two bulls, one ram, seven yearling lambs without blemish. The offerings for Israel's major agricultural festivals are standardized at this level — a consistency that ties together the three <em>chagim</em> into a single liturgical system.</p>",
    "28": "<p><strong>מִנְחָתָם</strong> (<em>minchatam</em>): 'their grain offering.' The Shavuot grain offering proportions are identical to those for Passover week (v.20): three-tenths per bull, two-tenths per ram. The standardization makes liturgical memory possible: once a worshipper learns the proportions for one festival, they know them for all. The precision of the sacrificial system serves the worshipper's formation as well as YHWH's honor.</p>",
    "29": "<p><strong>עִשָּׂרוֹן לַכֶּבֶשׂ הָאֶחָד</strong> (<em>issaron lakeves ha'echad</em>): 'one-tenth for each lamb.' For the seven Shavuot lambs, one-tenth of an ephah per lamb — consistent with all other festivals. The text's near-mechanical repetition of proportions is a feature, not a flaw: the precision is itself the content. YHWH's instructions are to be followed exactly, not approximately, because worship is a covenantal act where deviation from specification is covenant-infidelity.</p>",
    "30": "<p><strong>שְׂעִיר עִזִּים אֶחָד לְכַפֵּר עֲלֵיכֶם</strong> (<em>se'ir izzim echad lekapper aleikhem</em>, H3722): 'one male goat to make atonement for you.' <em>Kipper</em> (H3722, to atone, cover, expiate) — the theological core of the sin offering. The goat's blood and flesh perform the expiation of communal sin at each festival. The phrase <em>lekapper aleikhem</em> ('to make atonement for/on behalf of you') emphasizes that the atonement's benefit is corporate — the whole community is in view, not merely the individual offerers.</p>",
    "31": "<p><strong>מִלְּבַד עֹלַת הַתָּמִיד וּמִנְחָתוֹ תַּעֲשׂוּ</strong> (<em>milevad olat hatamid uminchat'o ta'asu</em>): 'in addition to the regular burnt offering and its grain offering you shall make.' The closing formula for the Weeks legislation. <em>Temimim yihyu lekhem v'niskeihem</em> — 'they shall be without blemish for you, and with their drink offerings.' The blemish-free requirement extends to the <em>tamid</em> as well. The chapter closes with a comprehensive statement: every festival offering stacks on the perpetual daily sacrifice, and all must be without blemish.</p>"
  },
  "29": {
    "1": "<p><strong>יוֹם תְּרוּעָה</strong> (<em>yom teru'ah</em>, H8643): 'a day of trumpet blasting / a day of loud shouting.' The first day of the seventh month (Tishri 1) is the <em>yom teru'ah</em> — the day of the <em>teru'ah</em> blast. <em>Teru'ah</em> (H8643) is the staccato, alarm-style blast of the trumpet (distinct from the sustained <em>teqi'ah</em>): it signals urgent gathering, divine approach, and battle alarm (Num 10:5-6). The seventh month is the most liturgically dense of the year: three major holy occasions fall within it (vv.1, 7, 12). The month begins with noise — the urgent, summoning call of the trumpet.</p>",
    "2": "<p><strong>וַעֲשִׂיתֶם עֹלָה לְרֵיחַ נִיחֹחַ לַיהוָה</strong> (<em>va'asitem olah lere'ach nichoach la-YHWH</em>): 'you shall make a burnt offering as a pleasing aroma to YHWH.' The Rosh Hashanah (Day of Trumpets) offering is notably smaller than the New Moon offering: one bull, one ram, seven lambs (vs. New Moon's two bulls, one ram, seven lambs). Yet it falls in the same <em>miqra-qodesh</em> (holy assembly) category. The specific shape of the offering is always determined by YHWH's command, not human calculation about what seems appropriate for the occasion's importance.</p>",
    "3": "<p><strong>מִנְחָתָם</strong> (<em>minchatam</em>): 'their grain offering.' The Day of Trumpets grain offering proportions: three-tenths per bull, two-tenths per ram — consistent with the other festival offerings. The repetition of familiar proportions gives the worshipper a stable, learnable system. The Sinai legislation is pedagogically structured: the same proportional grammar recurs throughout, forming liturgical habit through repetition.</p>",
    "4": "<p><strong>וְעִשָּׂרוֹן אֶחָד לַכֶּבֶשׂ הָאֶחָד</strong> (<em>v'issaron echad lakeves ha'echad</em>): 'one-tenth for each lamb.' One-tenth of an ephah of fine flour for each of the seven lambs of the Rosh Hashanah offering. The uniformity across festivals in the lamb grain offering (always one-tenth each) reflects a systematic logic: what is owed per lamb is fixed regardless of which festival it serves. Consistency in measure is a form of covenantal faithfulness.</p>",
    "5": "<p><strong>לְכַפֵּר עֲלֵיכֶם</strong> (<em>lekapper aleikhem</em>, H3722): 'to make atonement for you.' As with every festival (cf. 28:15, 22, 30), the sin offering goat at Rosh Hashanah effects corporate atonement. The seventh month's opening day begins with both the summoning <em>teru'ah</em> and the community's corporate expiation — the month that climaxes in Yom Kippur begins with a foretaste of atonement.</p>",
    "6": "<p><strong>מִלְּבַד עֹלַת הַחֹדֶשׁ וּמִנְחָתָהּ</strong> (<em>milevad olat hachodesh uminchatah</em>): 'in addition to the monthly burnt offering and its grain offering.' The layering principle: Rosh Hashanah falls on the first of the month, so both the New Moon offering (28:11-15) and the Rosh Hashanah offering are required simultaneously — stacked on the perpetual <em>tamid</em>. The day of the New Moon that opens the seventh month is the most heavily layered offering day outside Yom Kippur and Sukkot: daily + monthly + Rosh Hashanah offerings all brought together.</p>",
    "7": "<p><strong>בֶּעָשׂוֹר לַחֹדֶשׁ הַשְּׁבִיעִי הַזֶּה</strong> (<em>be'asor lachodesh hashvi'i hazeh</em>): 'on the tenth of this seventh month.' Yom Kippur — the Day of Atonement. <strong>וְעִנִּיתֶם אֶת-נַפְשֹׁתֵיכֶם</strong> (<em>v'initem et-nafshoteikhem</em>, H6031+H5315): 'you shall afflict your souls.' <em>Anah</em> (H6031, to afflict, humble, oppress) applied reflexively: Israel afflicts/humbles <em>herself</em>. <em>Nefesh</em> (H5315, soul, life, self) — the affliction is of the whole inner person, traditionally expressed through fasting. <strong>מְלָאכָה לֹא תַעֲשׂוּ</strong> (<em>melakhah lo ta'asu</em>): the prohibition here is stronger — <em>melakhah</em> without the qualifier <em>avodah</em> of the other festivals — suggesting total rest.</p>",
    "8": "<p><strong>וְהִקְרַבְתֶּם עֹלָה לַיהוָה</strong> (<em>vehiqravtem olah la-YHWH</em>): 'you shall present a burnt offering to YHWH.' The Yom Kippur communal offering: one bull, one ram, seven lambs (same as Rosh Hashanah). This is the public festival sacrifice; the unique Yom Kippur ritual of Lev 16 — with the high priest's two goats, the scapegoat, and the entry into the Holy of Holies — is not repeated here but referenced in v.11. These offerings are in addition to Lev 16's special rites, not a replacement for them.</p>",
    "9": "<p><strong>מִנְחָתָם</strong> (<em>minchatam</em>): 'their grain offering.' Yom Kippur grain offering proportions are identical to Rosh Hashanah (three-tenths/bull, two-tenths/ram). The consistency reinforces the system's memorability and signals that no one festival's animals are intrinsically more valuable than another's: the atonement's efficacy rests not in the scale of the offering but in YHWH's acceptance of it.</p>",
    "10": "<p><strong>עִשָּׂרוֹן לַכֶּבֶשׂ הָאֶחָד</strong> (<em>issaron lakeves ha'echad</em>): 'one-tenth for each of the seven lambs.' Standard lamb grain offering. The formulaic precision of these verses serves catechetical as well as liturgical purposes: the text trains Israel to associate specific measures with specific occasions, forming liturgical memory across generations.</p>",
    "11": "<p><strong>מִלְּבַד חַטַּאת הַכִּפֻּרִים</strong> (<em>milevad chatta't hakippurim</em>, H3725): 'in addition to the sin offering of the atonements.' The crucial phrase: the communal burnt and sin offerings of v.8-10 are <em>additional to</em> the <em>chatta't hakippurim</em> — the special Yom Kippur atonement ritual of Lev 16. The term <em>kippurim</em> (H3725) — a plural of intensity — appears only in the compound <em>Yom Kippurim</em> (Day of Atonements). The greatest annual atonement event combines the regular festival sacrifice system with the unrepeatable, once-per-year high-priestly entry into the Holy of Holies.</p>",
    "12": "<p><strong>בַּחֲמִשָּׁה עָשָׂר יוֹם לַחֹדֶשׁ הַשְּׁבִיעִי</strong> (<em>bachamisha asar yom lachodesh hashvi'i</em>): 'on the 15th of the seventh month.' Sukkot (Festival of Tabernacles/Booths) begins five days after Yom Kippur. <em>Chag la-YHWH</em> — 'a feast to YHWH.' Sukkot is the most joyful of the three <em>chagim</em> — the harvest festival (Deut 16:13-15 commands: 'you shall rejoice in your feast'). <em>Shivat yamim</em> — seven days — the longest of the festivals, reflecting the autumn harvest's significance as the culmination of Israel's agricultural year.</p>",
    "13": "<p><strong>שְׁלֹשָׁה עָשָׂר פָּרִים</strong> (<em>sheloshah asar parim</em>, H6499): 'thirteen young bulls.' Day 1 of Sukkot begins with thirteen bulls — the largest single-day animal offering in the entire liturgical calendar. Two rams and fourteen yearling lambs complete the burnt offering. The remarkable scale signals Sukkot's status as the premier harvest festival, celebrating YHWH's provision through the agricultural year. The rabbinic tradition associates the total 70 bulls offered across the seven days of Sukkot with the 70 nations of Gen 10 — Israel interceding for the nations at its greatest feast.</p>",
    "14": "<p><strong>שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר הָאֶחָד</strong> (<em>sheloshah esronim lapar ha'echad</em>): 'three-tenths for each bull.' Thirteen bulls means thirteen grain offerings of three-tenths each — 39 tenths of flour for the bulls alone on Sukkot Day 1. The scale of the grain offering matches the scale of the animal offering. <em>Bishetai esronim la'ayil ha'echad</em> — two-tenths for each of the two rams. The mathematical precision is sustained even when the numbers become very large.</p>",
    "15": "<p><strong>עִשָּׂרוֹן עִשָּׂרוֹן לַכֶּבֶשׂ הָאֶחָד</strong> (<em>issaron issaron lakeves ha'echad</em>): 'one-tenth for each lamb.' Fourteen lambs × one-tenth = 14 tenths. The total grain offering on Sukkot Day 1 is 39 (bulls) + 4 (rams) + 14 (lambs) = 57 tenths of an ephah. The sheer volume underscores the festival's grandeur. Every proportion is specified; nothing is left to approximation or improvisation.</p>",
    "16": "<p><strong>וּשְׂעִיר-עִזִּים אֶחָד חַטָּאת</strong> (<em>use'ir-izzim echad chatta't</em>): 'one male goat as a sin offering.' Even on Sukkot Day 1 — the grandest day of offering in the calendar — the sin offering goat is present. The juxtaposition of massive celebration (13 bulls) and the solitary sin offering goat expresses the two movements of Israel's worship: exuberant gratitude for provision and clear-eyed acknowledgment of sin. Both belong; neither can be omitted.</p>",
    "17": "<p><strong>וּבַיּוֹם הַשֵּׁנִי פָּרִים בְּנֵי-בָקָר שְׁנֵים עָשָׂר</strong> (<em>uvayom hasheni parim b'nei-vaqar shenim asar</em>): 'on the second day: twelve young bulls.' Sukkot Day 2 reduces by one bull (13 → 12). The descending sequence — 13, 12, 11, 10, 9, 8, 7 across the seven days — is unique in the sacrificial legislation; no other festival feature operates with a diminishing count. The rams (always two) and lambs (always fourteen) remain constant; only the bulls decrease. The pattern is given without explanation in the text itself.</p>",
    "18": "<p><strong>וּמִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>uminchatam veniskeihem</em>): 'their grain offerings and drink offerings.' The formula <em>kamishpatam</em> (H4941) — 'according to their ordinance/proper measure' — covers the grain and drink offerings for all the animals on Day 2. Once the proportional system is established (three-tenths/bull, two-tenths/ram, one-tenth/lamb), the text economizes: <em>kamishpatam</em> references the established proportions rather than repeating them in full for every day.</p>",
    "19": "<p><strong>וּשְׂעִיר-עִזִּים אֶחָד חַטָּאת</strong> (<em>use'ir-izzim echad chatta't</em>): 'one male goat as a sin offering.' Day 2's sin offering is identical to Day 1's. The constancy of the sin offering across all seven days — one goat, unchanged — while the bull count descends communicates a structural truth: the need for atonement does not decrease as the festival progresses. The celebration's joy increases in some sense (Israel moves deeper into the festival), but the acknowledgment of sin is no less necessary on Day 7 than on Day 1.</p>",
    "20": "<p><strong>וּבַיּוֹם הַשְּׁלִישִׁי פָּרִים אַחַד עָשָׂר</strong> (<em>uvayom hashlishi parim achad asar</em>): 'on the third day: eleven bulls.' The descending sequence continues. Day 3 brings 11 bulls — still more than any other festival (New Moon: 2; Passover week daily: 2; Shavuot: 2) — demonstrating that even the lowest point of Sukkot's bull offering exceeds the high points of other festivals. Sukkot's scale is categorically different from all other occasions in the calendar.</p>",
    "21": "<p><strong>וּמִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>uminchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em> again — according to their ordinance. The economy of the formula is the economy of mastery: the system is now so well-established that the full prescription can be abbreviated. Each day's offering set is uniquely specified (bull count) yet governed by the same proportional grammar (grain and drink offering amounts).</p>",
    "22": "<p><strong>וּשְׂעִיר אֶחָד חַטָּאת</strong> (<em>use'ir echad chatta't</em>): 'one goat as a sin offering.' Day 3 sin offering — unchanged. The goat holds constant through all seven days of Sukkot, through all the festival's variation. The sin offering is not diminished by repetition; its constancy is itself a theological statement about the permanent human condition requiring expiation.</p>",
    "23": "<p><strong>וּבַיּוֹם הָרְבִיעִי פָּרִים עֲשָׂרָה</strong> (<em>uvayom harvi'i parim asarah</em>): 'on the fourth day: ten bulls.' The midpoint of Sukkot. Ten is both the midpoint of the 13-7 sequence and a number with strong covenantal resonance in Israel: the ten words (commandments), ten plagues, ten spies. The fourth day reaches a round number — ten — that may function as the structural center of the week-long offering sequence.</p>",
    "24": "<p><strong>מִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>minchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em> — according to their ordinance. The structural economy of the repeated formula reinforces that the proportions are fixed law, not approximation. Israel does not negotiate the offering amounts; she executes the ordained measure precisely.</p>",
    "25": "<p><strong>וּשְׂעִיר-עִזִּים אֶחָד חַטָּאת</strong> (<em>use'ir-izzim echad chatta't</em>): 'one male goat as a sin offering.' Day 4 sin offering — invariant. The repetition of the identical sin offering against the backdrop of the declining bull sequence highlights the constancy of Israel's sinfulness relative to the variability of celebration. Festival intensity may fluctuate; the need for atonement does not.</p>",
    "26": "<p><strong>וּבַיּוֹם הַחֲמִישִׁי פָּרִים תִּשְׁעָה</strong> (<em>uvayom hachamishi parim tish'ah</em>): 'on the fifth day: nine bulls.' Nine bulls — the sequence descends from the high of thirteen toward the conclusion of seven. <em>Sheney eilim</em> and fourteen lambs remain constant, as they do throughout the week. The two rams may evoke covenant confirmation (covenant sacrifices often involved pairs: Gen 15; Exod 24) — their constancy through the week marks the unchanging covenantal ground of the festival.</p>",
    "27": "<p><strong>וּמִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>uminchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em>. By Day 5 of Sukkot, the worshipper has internalized the proportional system through four repetitions. The text's use of the abbreviated formula is a pedagogical feature: repetition with economy trains the worshipper in the grammar of sacrifice.</p>",
    "28": "<p><strong>וּשְׂעִיר אֶחָד חַטָּאת</strong> (<em>use'ir echad chatta't</em>): 'one goat as a sin offering.' Day 5 — constant. The sin offering's constancy throughout Sukkot's seven days may be read as a structural comment on the festival itself: Sukkot celebrates harvest abundance and divine provision, but abundance does not reduce the human need for atonement. The greatest feast of YHWH's provision is bracketed and pierced by the acknowledgment of human sin.</p>",
    "29": "<p><strong>וּבַיּוֹם הַשִּׁשִּׁי פָּרִים שְׁמֹנָה</strong> (<em>uvayom hashishi parim shmonah</em>): 'on the sixth day: eight bulls.' The penultimate day. Eight bulls — one more than the final day's seven. The sequence nears its completion: 13→12→11→10→9→8→7. Adding the bulls across all seven days gives 13+12+11+10+9+8+7 = 70. The number 70 resonates throughout Israel's story: 70 nations (Gen 10), 70 elders of Israel (Exod 24:9), 70 years of exile (Jer 25:11), 70 members of Jacob's family in Egypt (Gen 46:27). Rabbinic tradition connects the 70 Sukkot bulls to intercession for the 70 nations.</p>",
    "30": "<p><strong>מִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>minchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em>. The penultimate day follows the same proportional grammar as all the others. The system's consistency through six repetitions has fully formed the liturgical pattern in the reader's mind. Day 6's offerings are simply the prescribed measures applied to eight bulls, two rams, fourteen lambs.</p>",
    "31": "<p><strong>וּשְׂעִיר אֶחָד חַטָּאת</strong> (<em>use'ir echad chatta't</em>): 'one goat as a sin offering.' Day 6 — unchanged. The sixth day sin offering recalls the sixth day of creation (Gen 1:31), when God looked at all he had made and saw it was very good — yet even that good creation required, after the fall, the ongoing mechanism of atonement. Sukkot celebrates the fruit of a good creation, and the sin offering acknowledges that the creation's goodness does not eliminate the creature's sinfulness.</p>",
    "32": "<p><strong>וּבַיּוֹם הַשְּׁבִיעִי פָּרִים שִׁבְעָה</strong> (<em>uvayom hashvi'i parim shiv'ah</em>): 'on the seventh day: seven bulls.' The sequence completes: seven bulls on the seventh day. Seven is Israel's number of completion and covenant (seven-day week, seventh-year sabbatical, seventh-month festivals). The seven bulls bring the offering to a round conclusion. Total bulls over seven days: 70. The seventh day of Sukkot is called Hoshana Rabbah (Great Hosanna) in later tradition — a day of intense prayer and final sealing of the year's judgments.</p>",
    "33": "<p><strong>וּמִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>uminchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em> — the final repetition of the proportional formula within the seven-day sequence. By the seventh day, the worshipper has fully internalized the system. The repetition is no longer instruction but confirmation: the system has become the worshipper's liturgical native tongue.</p>",
    "34": "<p><strong>וּשְׂעִיר אֶחָד חַטָּאת</strong> (<em>use'ir echad chatta't</em>): 'one goat as a sin offering.' The final sin offering of the seven-day Sukkot sequence. Seven consecutive days, seven consecutive sin offerings — one per day, invariant. The seven-fold repetition creates an inescapable theological statement: each day of the most joyous festival in Israel's year requires its own act of atonement. Joy and confession are not opposites in Israel's worship; they are companions.</p>",
    "35": "<p><strong>בַּיּוֹם הַשְּׁמִינִי עֲצֶרֶת</strong> (<em>bayom hashmini atzeret</em>, H6116): 'on the eighth day: a closing assembly.' <em>Atzeret</em> (H6116) — from <em>atzar</em> (H6113, to restrain, hold back, retain, shut in). The <em>atzeret</em> is a gathering that holds the community in place one final day after the festival ends: the LORD detains his people for one more day in his presence. It is called <em>Shemini Atzeret</em> in later tradition. The eighth day is numerologically significant: beyond the week (7+1), beginning a new cycle, associated with covenant renewal and eschatological newness.</p>",
    "36": "<p><strong>אِשֶּׁה עֹלָה לְרֵיחַ נִיחֹחַ</strong> (<em>isheh olah lere'ach nichoach</em>): 'a fire offering, a burnt offering as a pleasing aroma.' The eighth day offering drops dramatically: one bull, one ram, seven lambs — a return to the minimal festival scale after the week's excess. After 70 bulls over seven days, the eighth day offers one. The contrast is intentional: the week of abundance ends; the <em>atzeret</em> is intimate. It is as though YHWH says: all the feast's grandeur has been offered — now hold back one more day with a simpler gift, just to be here.</p>",
    "37": "<p><strong>מִנְחָתָם וְנִסְכֵּיהֶם</strong> (<em>minchatam veniskeihem</em>): 'their grain offerings and drink offerings.' <em>Kamishpatam</em> — the final appearance of the proportional formula in the chapter. The eighth day grain and drink offerings follow the same proportions as all other festival offerings. Despite the reduction in animal scale, the quality requirements (<em>temimim</em>, without blemish) and the proportional grammar of the <em>minhah</em> remain unchanged. Intimacy does not diminish precision in Israel's worship.</p>",
    "38": "<p><strong>וּשְׂעִיר אֶחָד חַטָּאת</strong> (<em>use'ir echad chatta't</em>): 'one male goat as a sin offering.' The eighth day also has its sin offering — the final sin offering in the entire seventh-month festival sequence. The <em>atzeret</em> is not exempt from the acknowledgment of sin even in its final intimacy. Atonement is required as the people depart YHWH's festival presence, just as it was required upon entering it. The festival calendar begins and ends with the need for expiation.</p>",
    "39": "<p><strong>אֵלֶּה תַּעֲשׂוּ לַיהוָה בְּמוֹעֲדֵיכֶם</strong> (<em>eleh ta'asu la-YHWH bemoe'deikhem</em>, H4150): 'these you shall do for YHWH at your appointed festivals.' The closing summary of the entire festival calendar legislation (chs 28-29). <em>Mo'adim</em> (H4150, appointed times) — the festivals are not Israel's creation but YHWH's designated appointments: times he has set for covenant encounter. <em>Milevad nidreikhem u-nidvoteikhem</em> — 'in addition to your vow offerings and freewill offerings' — the mandatory calendar offerings are a floor, not a ceiling; personal votive and freewill offerings are not prohibited but additional.</p>",
    "40": "<p><strong>וַיֹּאמֶר מֹשֶׁה אֶל-בְּנֵי יִשְׂרָאֵל</strong> (<em>vayomer moshe el-b'nei yisrael</em>): 'Moses told the Israelites.' The closing transmission formula. Moses communicates to Israel everything YHWH commanded him — the standard chain of divine speech → Mosaic transmission → Israel's reception. The legislation of chs 28-29 (the complete festival sacrifice calendar) is thus passed from YHWH through Moses to the entire nation. The calendar is not priestly arcana but communal law: every Israelite is to know what YHWH requires at his appointed times.</p>"
  }
}

def main():
    existing = load_comm('original', 'numbers')
    merge_comm(existing, NUMBERS)
    save_comm('original', 'numbers', existing)
    for ch in ['27', '28', '29']:
        count = len(existing.get(ch, {}))
        print(f'ch {ch}: {count} verses in output')
    print('Numbers 27-29 original commentary written.')

if __name__ == '__main__':
    main()
